import React, { useState, useEffect, useRef } from 'react';
import { 
  Send, QrCode, Users, History, Settings, Coins, LogOut, CheckCircle2, 
  AlertCircle, Smartphone, ShieldCheck, LayoutDashboard, ArrowRight, 
  UploadCloud, User, Loader2, Lock, ChevronRight, PlusCircle, CreditCard, 
  Zap, ShoppingBag, Ticket, Image as ImageIcon, Film, X, Database, 
  Activity, Search, Edit, Trash2, MoreVertical, Save, ShieldAlert, 
  TrendingUp, MessageSquare, Server, Plus, Minus, Bell, RefreshCw,
  LogIn, FileText, Download, Play, Pause, Trash
} from 'lucide-react';

const API_URL = 'http://localhost:5000/api';

// Komponen QR Code menggunakan API luaran
const QRCodeImage = ({ value, size = 200 }) => {
  const qrUrl = `https://api.qrserver.com/v1/create-qr-code/?size=${size}x${size}&data=${encodeURIComponent(value)}`;
  return (
    <div className="bg-white p-4 rounded-3xl shadow-xl border border-slate-100 inline-block">
      <img src={qrUrl} alt="WhatsApp QR" width={size} height={size} className="rounded-xl" />
    </div>
  );
};

export default function App() {
  const [view, setView] = useState('login'); 
  const [user, setUser] = useState(null);
  const [token, setToken] = useState(localStorage.getItem('token'));

  // States
  const [formData, setFormData] = useState({ email: '', password: '', nama_syarikat: '' });
  const [loading, setLoading] = useState(false);
  const [message, setMessage] = useState({ type: '', text: '' });
  const [waStatus, setWaStatus] = useState('disconnected');
  const [qr, setQr] = useState(null);

  // States untuk Blast
  const [blastData, setBlastData] = useState({ numbers: '', message: '', file: null });
  const [blastStatus, setBlastStatus] = useState('idle'); // idle, sending, completed
  const [progress, setProgress] = useState(0);

  // Semak sesi
  useEffect(() => {
    const savedUser = localStorage.getItem('user');
    if (token && savedUser) {
      try {
        setUser(JSON.parse(savedUser));
        setView('dashboard');
      } catch (e) {
        localStorage.clear();
      }
    }
  }, [token]);

  // Auth Logic
  const handleAuth = async (e) => {
    e.preventDefault();
    setLoading(true);
    // Nota: Dalam demo ini kita simulasi jika backend belum sedia
    setTimeout(() => {
      if (formData.email === 'admin@arconnect.my' || view === 'register') {
        const mockUser = { id: '123', email: formData.email, nama_syarikat: formData.nama_syarikat || 'AR Connect User', kredit: 5000 };
        setUser(mockUser);
        setToken('mock-token');
        localStorage.setItem('user', JSON.stringify(mockUser));
        localStorage.setItem('token', 'mock-token');
        setView('dashboard');
      } else {
        setMessage({ type: 'error', text: 'Emel atau kata laluan salah.' });
      }
      setLoading(false);
    }, 1000);
  };

  const logout = () => {
    localStorage.clear();
    setUser(null);
    setToken(null);
    setView('login');
  };

  // WhatsApp Logic
  const connectWA = () => {
    setWaStatus('loading');
    setTimeout(() => {
      setQr('https://wa.me/qr/ARCONNECT_DEMO');
      setWaStatus('qr_ready');
    }, 1500);
  };

  // Blast Logic
  const startBlast = () => {
    if (!blastData.numbers || !blastData.message) {
      setMessage({ type: 'error', text: 'Sila masukkan nombor dan mesej.' });
      return;
    }
    setBlastStatus('sending');
    setProgress(0);
    const interval = setInterval(() => {
      setProgress(prev => {
        if (prev >= 100) {
          clearInterval(interval);
          setBlastStatus('completed');
          return 100;
        }
        return prev + 10;
      });
    }, 500);
  };

  // Components
  const SidebarItem = ({ id, icon: Icon, label }) => (
    <button 
      onClick={() => setView(id)}
      className={`flex items-center gap-4 w-full p-4 rounded-2xl font-black text-sm transition-all ${view === id ? 'bg-green-500 text-white shadow-lg shadow-green-100' : 'text-slate-400 hover:bg-slate-50 hover:text-slate-600'}`}
    >
      <Icon size={20} /> {label}
    </button>
  );

  // VIEW: LOGIN / REGISTER
  if (view === 'login' || view === 'register') {
    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center p-6">
        <div className="w-full max-w-md bg-white rounded-[3rem] p-10 shadow-2xl shadow-slate-200 border border-white">
          <div className="text-center mb-10">
            <div className="w-16 h-16 bg-green-500 rounded-2xl flex items-center justify-center mx-auto mb-4 rotate-3 shadow-lg shadow-green-200">
              <Zap size={32} className="text-white fill-current" />
            </div>
            <h1 className="text-3xl font-black tracking-tighter">AR CONNECT</h1>
            <p className="text-slate-400 font-bold text-xs uppercase tracking-widest mt-1">Professional WA Engine</p>
          </div>

          {message.text && (
            <div className={`p-4 rounded-2xl mb-6 text-xs font-bold flex items-center gap-2 ${message.type === 'error' ? 'bg-red-50 text-red-500' : 'bg-green-50 text-green-500'}`}>
              <AlertCircle size={16} /> {message.text}
            </div>
          )}

          <form onSubmit={handleAuth} className="space-y-4">
            {view === 'register' && (
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Nama Syarikat</label>
                <input required className="w-full p-5 bg-slate-50 rounded-2xl border-2 border-slate-50 focus:border-green-500 outline-none transition-all font-bold" placeholder="AR Global" onChange={e => setFormData({...formData, nama_syarikat: e.target.value})} />
              </div>
            )}
            <div className="space-y-2">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Email</label>
              <input type="email" required className="w-full p-5 bg-slate-50 rounded-2xl border-2 border-slate-50 focus:border-green-500 outline-none transition-all font-bold" placeholder="admin@arconnect.my" onChange={e => setFormData({...formData, email: e.target.value})} />
            </div>
            <div className="space-y-2">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Kata Laluan</label>
              <input type="password" required className="w-full p-5 bg-slate-50 rounded-2xl border-2 border-slate-50 focus:border-green-500 outline-none transition-all font-bold" placeholder="••••••••" onChange={e => setFormData({...formData, password: e.target.value})} />
            </div>

            <button disabled={loading} className="w-full py-5 bg-green-500 text-white rounded-2xl font-black shadow-xl shadow-green-100 flex items-center justify-center gap-2 hover:bg-green-600 transition-all uppercase tracking-widest mt-6">
              {loading ? <Loader2 className="animate-spin" /> : (view === 'login' ? <LogIn size={20}/> : <PlusCircle size={20}/>)}
              {view === 'login' ? 'Masuk Dashboard' : 'Daftar Sekarang'}
            </button>
          </form>

          <button onClick={() => setView(view === 'login' ? 'register' : 'login')} className="w-full mt-8 text-xs font-black text-slate-400 hover:text-green-500 uppercase tracking-widest transition">
            {view === 'login' ? 'Tiada akaun? Daftar sekarang' : 'Sudah ada akaun? Log masuk'}
          </button>
        </div>
      </div>
    );
  }

  // MAIN DASHBOARD LAYOUT
  return (
    <div className="min-h-screen bg-slate-50 flex text-slate-900 font-sans">
      {/* Sidebar */}
      <aside className="w-72 bg-white border-r border-slate-100 p-8 flex flex-col hidden lg:flex">
        <div className="flex items-center gap-3 mb-12">
          <div className="w-10 h-10 bg-green-500 rounded-xl flex items-center justify-center shadow-lg shadow-green-100">
            <Zap size={20} className="text-white fill-current" />
          </div>
          <h1 className="text-xl font-black tracking-tighter">AR CONNECT</h1>
        </div>

        <nav className="flex-1 space-y-2">
          <SidebarItem id="dashboard" icon={LayoutDashboard} label="Dashboard" />
          <SidebarItem id="blast" icon={Send} label="Fast Blast" />
          <SidebarItem id="contacts" icon={Users} label="Database" />
          <SidebarItem id="history" icon={History} label="Laporan" />
          <SidebarItem id="settings" icon={Settings} label="Tetapan" />
        </nav>

        <div className="mt-auto pt-8">
          <div className="bg-slate-900 rounded-[2rem] p-6 text-white relative overflow-hidden group">
            <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-1">Kredit Anda</p>
            <p className="text-2xl font-black mb-4">{user?.kredit?.toLocaleString() || 0}</p>
            <button className="w-full py-3 bg-white text-slate-900 rounded-xl font-black text-xs hover:bg-green-400 hover:text-white transition uppercase relative z-10">Tambah Kredit</button>
            <Coins className="absolute -right-4 -bottom-4 text-white opacity-5 rotate-12" size={100} />
          </div>
          <button onClick={logout} className="flex items-center gap-4 w-full p-4 mt-4 rounded-2xl font-black text-sm text-red-400 hover:bg-red-50 transition">
            <LogOut size={20} /> Log Keluar
          </button>
        </div>
      </aside>

      {/* Content */}
      <div className="flex-1 flex flex-col h-screen overflow-hidden">
        <header className="h-24 bg-white border-b border-slate-100 px-10 flex items-center justify-between flex-shrink-0">
          <div>
            <h2 className="text-xl font-black capitalize">{view}</h2>
            <p className="text-xs font-bold text-slate-400 uppercase tracking-widest">Portal / {user?.nama_syarikat}</p>
          </div>
          <div className="flex items-center gap-4">
            <div className="text-right hidden sm:block">
              <p className="text-sm font-black">{user?.nama_syarikat}</p>
              <p className="text-[10px] font-bold text-green-500 uppercase">Lesen Aktif</p>
            </div>
            <div className="w-12 h-12 bg-slate-100 rounded-2xl flex items-center justify-center border-2 border-white shadow-sm">
              <User size={20} className="text-slate-400" />
            </div>
          </div>
        </header>

        <main className="flex-1 overflow-y-auto p-10">
          {view === 'dashboard' && (
            <div className="max-w-6xl mx-auto space-y-10">
              <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                {[
                  { label: 'Jumlah Hantar', val: '12,402', color: 'blue', icon: Send },
                  { label: 'Kenalan', val: '4,820', color: 'green', icon: Users },
                  { label: 'Kadar Kejayaan', val: '98.2%', color: 'purple', icon: Activity },
                ].map((stat, i) => (
                  <div key={i} className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-slate-100 flex items-center gap-6">
                    <div className={`w-14 h-14 bg-${stat.color}-50 rounded-2xl flex items-center justify-center text-${stat.color}-500`}>
                      <stat.icon size={24} />
                    </div>
                    <div>
                      <p className="text-xs font-black text-slate-400 uppercase tracking-widest">{stat.label}</p>
                      <p className="text-2xl font-black">{stat.val}</p>
                    </div>
                  </div>
                ))}
              </div>

              <div className="grid grid-cols-1 lg:grid-cols-2 gap-10">
                <div className="bg-white rounded-[3.5rem] p-10 shadow-sm border border-slate-100">
                  <div className="flex items-center justify-between mb-10">
                    <h3 className="text-xl font-black flex items-center gap-3"><ShieldCheck className="text-green-500" /> Peranti WhatsApp</h3>
                    <span className={`px-4 py-1 rounded-full text-[10px] font-black uppercase ${waStatus === 'connected' ? 'bg-green-100 text-green-600' : 'bg-red-100 text-red-600'}`}>{waStatus}</span>
                  </div>

                  <div className="bg-slate-50 rounded-[3rem] p-12 flex flex-col items-center justify-center border-2 border-dashed border-slate-200 min-h-[400px]">
                    {waStatus === 'qr_ready' ? (
                      <div className="text-center space-y-6">
                        <QRCodeImage value={qr} />
                        <p className="text-sm font-bold text-slate-500">Imbas QR menggunakan WhatsApp anda</p>
                        <button onClick={() => setWaStatus('connected')} className="text-green-500 font-black text-xs uppercase tracking-widest">Sudah Imbas?</button>
                      </div>
                    ) : waStatus === 'connected' ? (
                      <div className="text-center">
                        <div className="w-24 h-24 bg-green-100 text-green-600 rounded-[2rem] flex items-center justify-center mx-auto mb-6 shadow-xl shadow-green-50">
                          <CheckCircle2 size={48} />
                        </div>
                        <h4 className="text-2xl font-black mb-2">Terhubung!</h4>
                        <p className="text-slate-400 font-bold text-sm mb-8">WhatsApp anda sedia untuk menghantar blast.</p>
                        <button onClick={() => setWaStatus('disconnected')} className="px-8 py-3 bg-red-50 text-red-500 rounded-xl font-black text-xs uppercase">Putuskan</button>
                      </div>
                    ) : (
                      <div className="text-center">
                        <div className="w-20 h-20 bg-slate-200 rounded-3xl flex items-center justify-center mx-auto mb-6 text-slate-400">
                          <QrCode size={40} />
                        </div>
                        <button onClick={connectWA} className="px-10 py-5 bg-slate-900 text-white rounded-2xl font-black hover:bg-green-500 transition-all shadow-xl shadow-slate-200 uppercase tracking-widest flex items-center gap-2">
                          {waStatus === 'loading' ? <RefreshCw className="animate-spin" /> : <Zap size={20} className="fill-current" />}
                          Sambung Enjin
                        </button>
                      </div>
                    )}
                  </div>
                </div>

                <div className="space-y-6">
                  <div className="bg-green-500 rounded-[3rem] p-10 text-white shadow-xl shadow-green-100 relative overflow-hidden group">
                    <h3 className="text-3xl font-black mb-4">Fast Blast</h3>
                    <p className="font-bold opacity-80 mb-10 max-w-[280px]">Hantar ribuan mesej serta-merta tanpa perlu simpan nombor.</p>
                    <button onClick={() => setView('blast')} className="px-10 py-4 bg-white text-green-600 rounded-2xl font-black uppercase text-sm shadow-lg hover:scale-105 transition-all flex items-center gap-2">
                      Mula Sekarang <ArrowRight size={18} />
                    </button>
                    <Send className="absolute -right-8 -bottom-8 opacity-10" size={220} />
                  </div>

                  <div className="bg-white border border-slate-100 rounded-[2.5rem] p-8">
                    <h3 className="font-black text-xs text-slate-400 uppercase tracking-widest mb-6 flex items-center gap-2"><Bell size={16}/> Notifikasi</h3>
                    <div className="space-y-4">
                      <div className="p-4 bg-blue-50 rounded-2xl flex gap-4 border border-blue-100">
                        <div className="w-10 h-10 bg-blue-500 rounded-xl flex-shrink-0 flex items-center justify-center text-white"><ShieldAlert size={20}/></div>
                        <div>
                          <p className="text-sm font-black text-slate-800">Tips Elak Ban</p>
                          <p className="text-[10px] font-bold text-slate-400">Gunakan selang masa 10-20 saat antara mesej.</p>
                        </div>
                      </div>
                    </div>
                  </div>
                </div>
              </div>
            </div>
          )}

          {view === 'blast' && (
            <div className="max-w-4xl mx-auto">
              <div className="bg-white rounded-[3.5rem] p-10 shadow-sm border border-slate-100">
                <div className="flex items-center gap-4 mb-10">
                  <div className="w-12 h-12 bg-green-500 text-white rounded-2xl flex items-center justify-center shadow-lg shadow-green-100"><Send size={24} /></div>
                  <div>
                    <h3 className="text-2xl font-black">Kempen Fast Blast</h3>
                    <p className="text-xs font-bold text-slate-400 uppercase tracking-widest">Hantar mesej pukal anda</p>
                  </div>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
                  <div className="space-y-6">
                    <div className="space-y-2">
                      <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Senarai Nombor (Asingkan dengan koma)</label>
                      <textarea 
                        className="w-full h-48 p-6 bg-slate-50 rounded-[2rem] border-2 border-slate-50 focus:border-green-500 outline-none transition-all font-bold text-sm resize-none"
                        placeholder="60123456789, 60198765432..."
                        value={blastData.numbers}
                        onChange={e => setBlastData({...blastData, numbers: e.target.value})}
                      />
                    </div>
                    <div className="p-6 bg-green-50 rounded-3xl border-2 border-dashed border-green-200 text-center group cursor-pointer hover:bg-green-100 transition-all">
                      <UploadCloud size={32} className="mx-auto text-green-500 mb-2 group-hover:-translate-y-1 transition-all" />
                      <p className="text-xs font-black text-green-600 uppercase tracking-widest">Muat Naik CSV / Excel</p>
                    </div>
                  </div>

                  <div className="space-y-6 flex flex-col">
                    <div className="space-y-2 flex-1 flex flex-col">
                      <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Mesej Anda</label>
                      <textarea 
                        className="w-full flex-1 p-6 bg-slate-50 rounded-[2rem] border-2 border-slate-50 focus:border-green-500 outline-none transition-all font-bold text-sm resize-none"
                        placeholder="Hai {nama}, terima kasih kerana..."
                        value={blastData.message}
                        onChange={e => setBlastData({...blastData, message: e.target.value})}
                      />
                    </div>

                    {blastStatus === 'sending' ? (
                      <div className="space-y-4">
                        <div className="w-full h-4 bg-slate-100 rounded-full overflow-hidden">
                          <div className="h-full bg-green-500 transition-all duration-500" style={{ width: `${progress}%` }}></div>
                        </div>
                        <p className="text-center text-xs font-black text-slate-400 uppercase tracking-widest">Menghantar... {progress}%</p>
                      </div>
                    ) : blastStatus === 'completed' ? (
                      <div className="p-4 bg-green-500 text-white rounded-2xl flex items-center justify-center gap-2 font-black uppercase text-xs tracking-widest">
                        <CheckCircle2 size={18} /> Misi Selesai!
                      </div>
                    ) : (
                      <button 
                        onClick={startBlast}
                        className="w-full py-5 bg-slate-900 text-white rounded-[2rem] font-black shadow-xl shadow-slate-200 flex items-center justify-center gap-3 hover:bg-green-500 transition-all uppercase tracking-widest"
                      >
                        <Play size={20} className="fill-current" /> Lancarkan Blast
                      </button>
                    )}
                  </div>
                </div>
              </div>
            </div>
          )}

          {view === 'contacts' && (
            <div className="max-w-5xl mx-auto space-y-6">
              <div className="flex items-center justify-between">
                <h3 className="text-2xl font-black">Database Kenalan</h3>
                <button className="px-6 py-3 bg-green-500 text-white rounded-xl font-black text-xs uppercase tracking-widest shadow-lg shadow-green-100 flex items-center gap-2">
                  <Plus size={18} /> Tambah Kenalan
                </button>
              </div>

              <div className="bg-white rounded-[3rem] shadow-sm border border-slate-100 overflow-hidden">
                <div className="p-8 border-b border-slate-50 flex items-center gap-4 bg-slate-50/50">
                  <div className="flex-1 relative">
                    <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                    <input className="w-full pl-12 pr-6 py-4 bg-white rounded-2xl border border-slate-100 outline-none focus:border-green-500 transition-all font-bold text-sm" placeholder="Cari nama atau nombor..." />
                  </div>
                  <button className="p-4 bg-white rounded-2xl border border-slate-100 text-slate-400 hover:text-slate-600"><Download size={20}/></button>
                </div>

                <div className="overflow-x-auto">
                  <table className="w-full text-left">
                    <thead>
                      <tr className="border-b border-slate-50">
                        <th className="p-8 text-[10px] font-black text-slate-400 uppercase tracking-widest">Nama / Bisnes</th>
                        <th className="p-8 text-[10px] font-black text-slate-400 uppercase tracking-widest">Nombor WhatsApp</th>
                        <th className="p-8 text-[10px] font-black text-slate-400 uppercase tracking-widest">Kumpulan</th>
                        <th className="p-8 text-[10px] font-black text-slate-400 uppercase tracking-widest text-right">Tindakan</th>
                      </tr>
                    </thead>
                    <tbody>
                      {[1,2,3].map(i => (
                        <tr key={i} className="border-b border-slate-50 hover:bg-slate-50 transition-all group">
                          <td className="p-8">
                            <div className="flex items-center gap-4">
                              <div className="w-10 h-10 bg-slate-100 rounded-xl flex items-center justify-center font-black text-slate-400">#</div>
                              <p className="text-sm font-black text-slate-800">Pelanggan Demo {i}</p>
                            </div>
                          </td>
                          <td className="p-8 font-bold text-sm text-slate-600">6012345678{i}</td>
                          <td className="p-8">
                            <span className="px-3 py-1 bg-blue-50 text-blue-500 rounded-lg text-[10px] font-black uppercase">Lead</span>
                          </td>
                          <td className="p-8 text-right">
                            <div className="flex items-center justify-end gap-2 opacity-0 group-hover:opacity-100 transition-all">
                              <button className="p-2 text-slate-400 hover:text-blue-500 transition"><Edit size={18}/></button>
                              <button className="p-2 text-slate-400 hover:text-red-500 transition"><Trash size={18}/></button>
                            </div>
                          </td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              </div>
            </div>
          )}

          {/* Placeholder for other views */}
          {['history', 'settings'].includes(view) && (
            <div className="flex flex-col items-center justify-center h-full text-center">
              <div className="w-24 h-24 bg-slate-100 rounded-[2rem] flex items-center justify-center text-slate-300 mb-6">
                <Database size={40} />
              </div>
              <h3 className="text-2xl font-black">Modul {view.toUpperCase()}</h3>
              <p className="text-slate-400 font-bold max-w-sm mt-2 uppercase text-[10px] tracking-[0.2em]">Pembangunan Sedang Dijalankan</p>
              <button onClick={() => setView('dashboard')} className="mt-8 text-green-500 font-black uppercase text-xs tracking-widest flex items-center gap-2 hover:gap-4 transition-all">
                Kembali ke Dashboard <ArrowRight size={16} />
              </button>
            </div>
          )}
        </main>
      </div>
    </div>
  );
}
